// Subquery 사용 (권장)
public static Specification<Article> hasFavoritedUsername(String favoritedUsername) {
    return (root, query, cb) -> {
        if (favoritedUsername == null) return cb.conjunction();
        Subquery<UUID> subquery = query.subquery(UUID.class);
        Root<ArticleFavorite> favoriteRoot = subquery.from(ArticleFavorite.class);
        subquery.select(favoriteRoot.get("article").get("id"))
                .where(cb.equal(favoriteRoot.get("user").get("username"), favoritedUsername));
        return root.get("id").in(subquery);
    };
}

