// Locale.ROOT + NFKD 정규화 + collision retry
private static String titleToSlug(String title) {
    String normalized = Normalizer.normalize(title, Normalizer.Form.NFKD)
            .replaceAll("\\p{InCombiningDiacriticalMarks}+", "");
    String slug = normalized.toLowerCase(Locale.ROOT)
            .replaceAll("[^a-z0-9\\s-]", "")
            .replaceAll("\\s+", "-")
            .replaceAll("-+", "-");
    return slug;
}

// collision retry (Service 단)
private String generateUniqueSlug(String title) {
    String slug = titleToSlug(title);
    int suffix = 0;
    while (articleRepository.existsBySlug(slug)) {
        suffix++;
        slug = titleToSlug(title) + "-" + suffix;
    }
    return slug;
}

